INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-02442', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地法所稱不在地主，不包括下列何種情形？', '["土地所有權人及家屬因災難離開土地所在地之直轄市或縣（市），繼續滿三年者", "共有土地之共有人全體離開其所在地之直轄市或縣（市），繼續滿一年者", "土地所有權人及其家屬離開其土地所在地之直轄市或縣（市），繼續滿五年者", "營業組合所有土地，其組合於其土地所在地之直轄市或縣（市）停止營業，繼續滿一年者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02443', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲於己地，自建房屋。屋內有書房一間，屋房內置有一檜木書桌，書桌有兩個抽屜。桌上有一個新力牌 DVD錄放影機，並有七片電影DVD。全屋地板鋪以羅馬磁磚，其上有一落地燈，配以法國進口的燈罩。 試問下列論述中何者為主物與從物關係？', '["房屋與書房", "書桌與抽屜", "DVD錄放影機與七片電影DVD", "落地燈與法國進口燈罩"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02444', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '書商甲寄當季書單價目表給乙，乙經過審慎考慮，勾選自己所需要的書單，並將該書單放進信封，之後 放置書桌上。隔天乙上班途中，經過郵局時，將該信件投入信箱。該信件於三日後到達書商甲處。乙發 出之要約何時發生效力？', '["勾選書單完畢時", "書單放進信封時", "信件投入信箱時", "信件到達書商甲時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02445', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列對於代理的論述，何者錯誤？', '["以本人名義所為的法律行為，直接對本人發生法律效力", "法定代理人有受領清償的權限", "所謂的復代理，係指代理人以其名義將代理權再授與他人，為我國法律所允許並無例外", "有代理權的甲，以自己名義幫委任人乙購買一部腳踏車，雖然甲有代理權，但該購買行為仍不屬代理 行為，對於乙不生效力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02446', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列對於得撤銷的法律行為之論述，何者正確？', '["財產法律行為一經撤銷，自撤銷意思表示時起，向後發生效力", "錯誤意思表示，表意人得於發現錯誤後二年內，撤銷其法律行為", "撤銷權為形成權，撤銷權之行使為單獨行為，所以表意人得單方對相對人為撤銷之意思表示，不須經 相對人之同意", "錯誤意思表示之撤銷，表意人對於撤銷原因明知或可得而知之相對人，仍負有損害賠償責任"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02447', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲上班途中，見乙受傷昏迷在地，甲雖不認識乙，但仍非常熱心開車載乙到醫院急救。請問甲乙間之法 律關係如何？', '["委任關係", "無因管理", "不當得利", "無權代理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02448', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙訂立電腦買賣契約，但買受人甲才十五歲，甲的父母事後拒絕承認該契約。試問甲乙間的法律關係如何？', '["乙可以契約無效，主張甲的占有電腦為無權占有，而主張所有物返還請求權", "乙可以契約無效，主張甲的占有電腦為侵權行為，而主張回復原狀的損害賠償責任", "乙可以契約無效，主張甲的占有電腦為不當得利，而主張不當得利的返還", "乙可以契約無效，主張甲的占有電腦為無因管理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02449', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲酒駕，不慎撞傷路人乙，乙因此必須住院治療，一個月無法工作，試問下列對於甲乙關係的論述何者錯誤？', '["甲因酒駕撞傷乙，致乙受有身體傷害住院，甲對乙構成侵權行為責任", "乙對甲可以要求醫療費用之損害賠償", "乙住院期間，需要僱用看護照顧，乙可以請求甲負擔該費用", "乙為藝術工作者，因為受傷而無法開演唱會，乙的經紀人丙因無法開演唱會，而受有嚴重損失。丙可 以對甲請求丙因乙無法開演唱會所受的損失賠償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02450', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列對於債之標的的論述何者正確？', '["乙為出售中古屋的出售者，甲向乙購買乙所出售的A屋，甲乙間成立種類買賣", "甲乙訂立契約，約定甲對乙負有給付新台幣五千元的債務，甲對乙成立貨幣之債，亦稱金錢之債", "任意之債，係指債權人得於數宗給付中，自由選擇其中一種為給付標的", "甲乙雖然訂立A畫的買賣契約，但約定債務人乙也可以B畫替代交付，甲乙間成立選擇之債"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02451', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲出賣一隻種豬給乙，交付的種豬有口蹄疫，致乙的豬群遭受感染，而全部銷毀。請問乙對甲可以請求 何種損害賠償？', '["給付遲延的損害賠償", "不完全給付的損害賠償", "受領遲延的損害賠償", "給付不能的損害賠償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
